#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        static char s[200005]; scanf("%s", s);
        long long ans = 0; int cnt = 0;
        for(int i=0;i<N;i++){
            if(s[i]=='0') cnt++; else { ans += cnt / K; cnt = 0; }
        }
        ans += cnt / K;
        printf("%lld\n", ans);
    }
    return 0;
}

