const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const s = input[idx++];
  let ans = 0;
  let cnt = 0;
  for (let i = 0; i < N; i++) {
    if (s[i] === '0') cnt++; else { ans += Math.floor(cnt / K); cnt = 0; }
  }
  ans += Math.floor(cnt / K);
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));
